package main

import (
    "net/http"
    "time"
)

// Noncompliant: Cookie without HttpOnly flag
func setSessionCookie(w http.ResponseWriter, sessionID string) {
    cookie := &http.Cookie{
        Name:     "session_id",
        Value:    sessionID,
        Path:     "/",
        Expires:  time.Now().Add(24 * time.Hour),
        // BAD: Missing HttpOnly flag - vulnerable to XSS attacks
    }
    http.SetCookie(w, cookie)
}

func setAuthCookie(w http.ResponseWriter, token string) {
    // BAD: Authentication cookie accessible via JavaScript
    cookie := &http.Cookie{
        Name:    "auth_token",
        Value:   token,
        Path:    "/",
        Secure:  true,
        HttpOnly: false, // Explicitly set to false - BAD
    }
    http.SetCookie(w, cookie)
}

