package main

import (
    "net/http"
    "time"
)

// Compliant: Cookie with HttpOnly flag
func setSessionCookie(w http.ResponseWriter, sessionID string) {
    cookie := &http.Cookie{
        Name:     "session_id",
        Value:    sessionID,
        Path:     "/",
        Expires:  time.Now().Add(24 * time.Hour),
        HttpOnly: true, // GOOD: Prevents client-side script access
        Secure:   true, // Also good practice for HTTPS
    }
    http.SetCookie(w, cookie)
}

func setAuthCookie(w http.ResponseWriter, token string) {
    // GOOD: Authentication cookie protected from XSS
    cookie := &http.Cookie{
        Name:     "auth_token",
        Value:    token,
        Path:     "/",
        Secure:   true,
        HttpOnly: true, // GOOD: Script access prevented
        SameSite: http.SameSiteStrictMode,
    }
    http.SetCookie(w, cookie)
}
